#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
using namespace std;
CI MAXN=1e3+5,dx[]={1,-1,0,0},dy[]={0,0,1,-1};
char c[MAXN][MAXN],ans=0;
int n,sx,sy,ex,ey,vis[MAXN][MAXN],TIMES[MAXN][MAXN];
struct node
{
	int x,y;
}; 
void BFS()
{
	queue<PII> q;
	q.push(make_pair(sx,sy));
	TIMES[sx][sy]=0;
	vis[sx][sy]=true;
	while(q.size())
	{ 
		int now_x=q.front().first;
		int now_y=q.front().second;
		q.pop();
		for(int i=0;i<4;++i)
		{
			int new_x=now_x+dx[i];
			int new_y=now_y+dy[i];
			if(new_x==ex&&new_y==ey)
			{
				printf("%d",TIMES[now_x][now_y]+1);
				return;
			}
			if(!(new_x<1||new_y<1||new_x>n||new_y>n||vis[new_x][new_y]||c[new_x][new_y]!='0'))
			{
				q.push(make_pair(new_x,new_y));
				TIMES[new_x][new_y]=TIMES[now_x][now_y]+1;
				vis[new_x][new_y]=true;
			}
		}
	}
	return;
}
int main(void){
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	memset(vis,false,sizeof vis);
	scanf("%d\n",&n);
	for(int i=1;i<=n;++i)
	{
		for(int j=1;j<=n;++j)
		{
			cin>>c[i][j];
		}
	}
	scanf("%d%d%d%d",&sx,&sy,&ex,&ey);
	BFS();
	return false;
}
